#!/usr/bin/env node
/**
 * Manual test script for mittwald_domain_virtualhost_list tool
 *
 * This script tests the tool with both valid and invalid parameters
 */

import Anthropic from '@anthropic-ai/sdk';

const MCP_SERVER_URL = process.env.MCP_SERVER_URL || 'https://mittwald-mcp-fly2.fly.dev/mcp';

async function testDomainVirtualHostList() {
  console.log('Testing mittwald_domain_virtualhost_list tool...\n');

  const client = new Anthropic({
    apiKey: process.env.ANTHROPIC_API_KEY,
  });

  // Test 1: Get a valid project ID first
  console.log('Test 1: Getting valid project ID...');
  try {
    const projectListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_list tool to list all projects. Return ONLY the first project ID from the response in the format: PROJECT_ID=<id>'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_list',
        description: 'List all projects',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('Project list response:');
    console.log(JSON.stringify(projectListMessage, null, 2));
    console.log('\n---\n');

    // Extract project ID from response
    let projectId: string | null = null;
    for (const block of projectListMessage.content) {
      if (block.type === 'text' && block.text.includes('PROJECT_ID=')) {
        const match = block.text.match(/PROJECT_ID=([a-f0-9-]+)/);
        if (match) {
          projectId = match[1];
          break;
        }
      }
    }

    if (!projectId) {
      console.log('No project ID found in response. Will use fallback ID for testing.');
      projectId = 'p-test-invalid';
    } else {
      console.log(`Found project ID: ${projectId}\n`);
    }

    // Test 2: Call virtualhost list with valid project ID
    console.log(`Test 2: Calling mittwald_domain_virtualhost_list with projectId="${projectId}"...`);
    const validTestMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: `Use the mittwald_domain_virtualhost_list tool with projectId="${projectId}". Return the complete response.`
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_domain_virtualhost_list',
        description: 'List domain virtual hosts for a project',
        input_schema: {
          type: 'object',
          properties: {
            projectId: {
              type: 'string',
              description: 'The project ID'
            }
          },
          required: ['projectId']
        }
      }]
    });

    console.log('Valid project ID response:');
    console.log(JSON.stringify(validTestMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during valid parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  // Test 3: Call with invalid project ID
  console.log('Test 3: Calling mittwald_domain_virtualhost_list with invalid projectId...');
  try {
    const invalidTestMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_domain_virtualhost_list tool with projectId="p-invalid-12345". Return the complete response including any errors.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_domain_virtualhost_list',
        description: 'List domain virtual hosts for a project',
        input_schema: {
          type: 'object',
          properties: {
            projectId: {
              type: 'string',
              description: 'The project ID'
            }
          },
          required: ['projectId']
        }
      }]
    });

    console.log('Invalid project ID response:');
    console.log(JSON.stringify(invalidTestMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during invalid parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  // Test 4: Call without required projectId parameter
  console.log('Test 4: Calling mittwald_domain_virtualhost_list without projectId...');
  try {
    const missingParamMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Try to use the mittwald_domain_virtualhost_list tool without providing the projectId parameter. Report what happens.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_domain_virtualhost_list',
        description: 'List domain virtual hosts for a project',
        input_schema: {
          type: 'object',
          properties: {
            projectId: {
              type: 'string',
              description: 'The project ID'
            }
          },
          required: ['projectId']
        }
      }]
    });

    console.log('Missing parameter response:');
    console.log(JSON.stringify(missingParamMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during missing parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  console.log('\nAll tests completed!');
}

// Run the test
testDomainVirtualHostList().catch(console.error);

